func solve(nums []int64) int64 {
	n := len(nums)
	if n == 1 {
		return 0
	}

	primeToIndices := make(map[int64][]int)
	for i, num := range nums {
		if isPrime(num) {
			primeToIndices[num] = append(primeToIndices[num], i)
		}
	}

	divisibleIndices := make(map[int64][]int)
	for i, num := range nums {
		for p := range primeToIndices {
			if num%p == 0 && num != p {
				divisibleIndices[p] = append(divisibleIndices[p], i)
			}
		}
	}

	dist := make([]int64, n)
	for i := range dist {
		dist[i] = 1 << 30
	}
	dist[0] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{value: 0, priority: dist[0]})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		u := item.value
		if u == n-1 {
			return dist[u]
		}
		if dist[u] < item.priority {
			continue
		}

		// Check adjacent moves
		if u+1 < n && dist[u+1] > dist[u]+1 {
			dist[u+1] = dist[u] + 1
			heap.Push(&pq, &Item{value: u + 1, priority: dist[u+1]})
		}
		if u-1 >= 0 && dist[u-1] > dist[u]+1 {
			dist[u-1] = dist[u] + 1
			heap.Push(&pq, &Item{value: u - 1, priority: dist[u-1]})
		}

		// Check prime teleportation
		num := nums[u]
		if isPrime(num) {
			for _, j := range divisibleIndices[num] {
